<script lang="ts">
  import {addCardDocumentAsset,addCardLoreEntry,buildEditedRoots,createCardDocument,exportCardDocument,removeCardDocumentAsset,removeCardLoreEntry,updateCardDocument,type CardDocument,type ParsedCard} from '@simbot/card';
  import Icon from '@simbot/ui/Icon.svelte';
  import EditorPage from '../editor/EditorPage.svelte';
  import {onDestroy,untrack} from 'svelte';

  let {parsed,projectId,onsave,onclose}:{parsed:ParsedCard;projectId:string;onsave:(parsed:ParsedCard)=>Promise<void>;onclose:()=>void}=$props();
  const initialParsed=untrack(()=>parsed);
  let document=$state.raw<CardDocument>(createCardDocument(initialParsed)),revision=$state(0),tab=$state<'basic'|'greetings'|'lore'|'assets'|'scripts'|'advanced'|'simulation'>('basic'),saving=$state(false),notice=$state(''),rawText=$state(JSON.stringify(initialParsed.card,null,2)),triggerText=$state(JSON.stringify(createCardDocument(initialParsed).draft.triggerScripts,null,2)),assetInput=$state<HTMLInputElement>(),filter=$state(''),limit=$state(80),localUrls=new Map<string,string>();
  const tabs=[['basic','기본 정보'],['greetings','첫 메시지'],['lore','로어북'],['assets','에셋'],['scripts','스크립트'],['advanced','고급 원본'],['simulation','시뮬레이션']] as const;
  let visibleAssets=$derived(document.draft.assets.filter(asset=>!asset.deleted&&(!filter.trim()||`${asset.name} ${asset.type} ${asset.ext}`.toLocaleLowerCase().includes(filter.trim().toLocaleLowerCase()))).slice(0,limit));
  onDestroy(()=>{for(const url of localUrls.values())URL.revokeObjectURL(url);});
  function mutate(change:(draft:CardDocument['draft'])=>void){updateCardDocument(document,change);revision+=1;notice='저장되지 않은 변경사항';}
  function field<K extends keyof CardDocument['draft']>(key:K,value:CardDocument['draft'][K]){mutate(draft=>{draft[key]=value;});}
  function assetUrl(id:string){const asset=document.draft.assets.find(value=>value.id===id);if(!asset?.bytes||!asset.mime.startsWith('image/'))return'';const old=localUrls.get(id);if(old)return old;const url=URL.createObjectURL(new Blob([Uint8Array.from(asset.bytes)],{type:asset.mime}));localUrls.set(id,url);return url;}
  async function addAssets(event:Event){const files=[...(event.currentTarget as HTMLInputElement).files??[]];for(const file of files)addCardDocumentAsset(document,{name:file.name,type:file.type,bytes:new Uint8Array(await file.arrayBuffer())},file.type.startsWith('image/')?'image':'asset');revision+=1;notice=`에셋 ${files.length}개 추가됨`;if(assetInput)assetInput.value='';}
  async function save(){saving=true;try{const result=exportCardDocument(document);await onsave(result.parsed);document=createCardDocument(result.parsed);rawText=JSON.stringify(result.parsed.card,null,2);triggerText=JSON.stringify(document.draft.triggerScripts,null,2);revision+=1;notice='카드에 저장했습니다.';}catch(reason){notice=reason instanceof Error?reason.message:String(reason);}finally{saving=false;}}
  function download(){try{const result=exportCardDocument(document),url=URL.createObjectURL(new Blob([Uint8Array.from(result.bytes)],{type:'application/octet-stream'})),anchor=globalThis.document.createElement('a');anchor.href=url;anchor.download=`${document.draft.name||'card'}.${document.source.format==='jpeg'?'jpg':document.source.format}`;anchor.click();setTimeout(()=>URL.revokeObjectURL(url),1000);}catch(reason){notice=reason instanceof Error?reason.message:String(reason);}}
  function applyRaw(){try{const card=JSON.parse(rawText) as Record<string,unknown>,next=createCardDocument({...document.source,card,name:String((card.data as Record<string,unknown>|undefined)?.name??card.name??document.source.name)});document.cardRoot=card;document.draft={...next.draft,assets:document.draft.assets};document.revision+=1;document.dirty=true;revision+=1;notice='원본 JSON을 편집 초안에 적용했습니다.';}catch(reason){notice=`JSON 오류: ${reason instanceof Error?reason.message:String(reason)}`;}}
  function syncRaw(){const roots=buildEditedRoots(document);rawText=JSON.stringify(roots.root,null,2);}
  function addRegex(){mutate(draft=>draft.regexScripts.push({in:'',out:'',type:'editdisplay',flag:'g',comment:'새 정규식'}));}
  function applyTriggers(){try{const value=JSON.parse(triggerText)as unknown;if(!Array.isArray(value)||value.some(item=>!item||typeof item!=='object'||Array.isArray(item)))throw new Error('배열 형식이어야 합니다.');mutate(draft=>draft.triggerScripts=structuredClone(value)as Record<string,unknown>[]);notice=`트리거 스크립트 ${value.length}개를 초안에 적용했습니다.`;}catch(reason){notice=`트리거 JSON 오류: ${reason instanceof Error?reason.message:String(reason)}`;}}
</script>

<div class="scrim" role="presentation" onclick={(event)=>{if(event.target===event.currentTarget)onclose();}}>
  <section class="workspace" aria-label="봇 편집기">
    <header><div><strong>{document.draft.name||'이름 없는 봇'}</strong><small>{projectId} · revision {document.revision}</small></div><span class:dirty={document.dirty}>{notice||'카드 원본을 보존하며 편집합니다.'}</span><button onclick={download}>파일로 내보내기</button><button class="save" disabled={saving||!document.dirty} onclick={()=>void save()}>{saving?'저장 중…':'카드 저장'}</button><button class="close" aria-label="닫기" onclick={onclose}>×</button></header>
    <nav>{#each tabs as item}<button class:active={tab===item[0]} onclick={()=>{tab=item[0];if(item[0]==='advanced')syncRaw();}}>{item[1]}</button>{/each}</nav>
    <main>
      {#if tab==='basic'}<section class="form"><h2>기본 정보</h2><label>제목<input value={document.draft.name} oninput={event=>field('name',event.currentTarget.value)}/></label><label>설명<textarea rows="8" value={document.draft.description} oninput={event=>field('description',event.currentTarget.value)}></textarea></label><label>성격<textarea rows="6" value={document.draft.personality} oninput={event=>field('personality',event.currentTarget.value)}></textarea></label><label>시나리오<textarea rows="6" value={document.draft.scenario} oninput={event=>field('scenario',event.currentTarget.value)}></textarea></label><label>태그<input value={document.draft.tags.join(', ')} oninput={event=>field('tags',event.currentTarget.value.split(',').map(value=>value.trim()).filter(Boolean))}/></label><label>제작자 메모<textarea rows="5" value={document.draft.creatorNotes} oninput={event=>field('creatorNotes',event.currentTarget.value)}></textarea></label></section>
      {:else if tab==='greetings'}<section class="form"><h2>첫 메시지</h2><p>새 채팅을 만들 때 표시되는 시작 장면입니다.</p><textarea rows="14" value={document.draft.firstMessage} oninput={event=>field('firstMessage',event.currentTarget.value)}></textarea><h3>대체 첫 메시지</h3>{#each document.draft.alternateGreetings as greeting,index}<article class="greeting"><textarea rows="8" value={greeting} oninput={event=>mutate(draft=>draft.alternateGreetings[index]=event.currentTarget.value)}></textarea><button onclick={()=>mutate(draft=>draft.alternateGreetings.splice(index,1))}><Icon name="trash"/> 삭제</button></article>{/each}<button class="add" onclick={()=>mutate(draft=>draft.alternateGreetings.push(''))}><Icon name="plus"/> 대체 메시지 추가</button></section>
      {:else if tab==='lore'}<section><div class="section-head"><div><h2>로어북</h2><p>{document.draft.lorebook.length}개 항목 · 원본 확장 필드도 함께 보존됩니다.</p></div><button class="add" onclick={()=>{addCardLoreEntry(document);revision+=1;notice='새 로어 추가됨';}}><Icon name="plus"/> 항목 추가</button></div><div class="lore-list">{#each document.draft.lorebook as entry,index(entry.id)}<details><summary><input type="checkbox" checked={entry.enabled} onclick={event=>event.stopPropagation()} onchange={event=>mutate(draft=>draft.lorebook[index]!.enabled=event.currentTarget.checked)}/><strong>{entry.name||'이름 없는 로어'}</strong><small>{entry.keys.join(', ')||'활성 키 없음'}</small></summary><div class="lore-form"><label>이름<input value={entry.name} oninput={event=>mutate(draft=>draft.lorebook[index]!.name=event.currentTarget.value)}/></label><label>활성 키<input value={entry.keys.join(', ')} oninput={event=>mutate(draft=>draft.lorebook[index]!.keys=event.currentTarget.value.split(',').map(value=>value.trim()).filter(Boolean))}/></label><label>보조 키<input value={entry.secondaryKeys.join(', ')} oninput={event=>mutate(draft=>draft.lorebook[index]!.secondaryKeys=event.currentTarget.value.split(',').map(value=>value.trim()).filter(Boolean))}/></label><label>내용<textarea rows="10" value={entry.content} oninput={event=>mutate(draft=>draft.lorebook[index]!.content=event.currentTarget.value)}></textarea></label><div class="checks"><label><input type="checkbox" checked={entry.constant} onchange={event=>mutate(draft=>draft.lorebook[index]!.constant=event.currentTarget.checked)}/> 항상 활성</label><label><input type="checkbox" checked={entry.selective} onchange={event=>mutate(draft=>draft.lorebook[index]!.selective=event.currentTarget.checked)}/> 선택적</label><label><input type="checkbox" checked={entry.useRegex} onchange={event=>mutate(draft=>draft.lorebook[index]!.useRegex=event.currentTarget.checked)}/> 정규식 키</label></div><button class="danger" onclick={()=>{removeCardLoreEntry(document,entry.id);revision+=1;}}><Icon name="trash"/> 삭제</button></div></details>{/each}</div></section>
      {:else if tab==='assets'}<section><div class="section-head"><div><h2>에셋</h2><p>{document.draft.assets.filter(asset=>!asset.deleted).length}개 · 이미지는 보일 때만 불러옵니다.</p></div><button class="add" onclick={()=>assetInput?.click()}><Icon name="plus"/> 파일 추가</button><input class="hidden" bind:this={assetInput} type="file" multiple accept="image/*,audio/*,video/*" onchange={addAssets}/></div><input class="search" bind:value={filter} placeholder="이름·종류·확장자 검색"/><div class="assets">{#each visibleAssets as asset(asset.id)}<article>{#if asset.mime.startsWith('image/')}<img src={assetUrl(asset.id)} alt={asset.name} loading="lazy"/>{:else}<div class="file"><Icon name="badge"/><span>{asset.ext}</span></div>{/if}<input value={asset.name} aria-label="에셋 이름" oninput={event=>mutate(draft=>{const target=draft.assets.find(value=>value.id===asset.id);if(target)target.name=event.currentTarget.value;})}/><select value={asset.type} onchange={event=>mutate(draft=>{const target=draft.assets.find(value=>value.id===asset.id);if(target)target.type=event.currentTarget.value;})}><option value="icon">아이콘</option><option value="emotion">감정</option><option value="background">배경</option><option value="image">이미지</option><option value="asset">기타</option></select><small>{asset.ext} · {Math.ceil(asset.size/1024).toLocaleString()}KB</small><button class="danger" onclick={()=>{removeCardDocumentAsset(document,asset.id);revision+=1;}}><Icon name="trash"/> 삭제</button></article>{/each}</div>{#if visibleAssets.length<document.draft.assets.filter(asset=>!asset.deleted).length}<button class="add more" onclick={()=>limit+=80}>80개 더 보기</button>{/if}</section>
      {:else if tab==='scripts'}<section class="form"><h2>스크립트</h2><p>리스의 백그라운드 임베딩과 정규식은 안전한 호환 계층에서 작동합니다. 트리거 스크립트는 현재 원본을 보존·편집할 수 있지만, 임의 Lua나 JavaScript는 실행하지 않습니다.</p><label>백그라운드 임베딩 HTML/CSS<textarea rows="14" value={document.draft.backgroundHtml} oninput={event=>field('backgroundHtml',event.currentTarget.value)}></textarea></label><div class="section-head"><h3>정규식 스크립트 · {document.draft.regexScripts.length}개</h3><button class="add" onclick={addRegex}><Icon name="plus"/> 추가</button></div>{#each document.draft.regexScripts as script,index}<article class="regex"><div><input placeholder="설명" value={script.comment} oninput={event=>mutate(draft=>draft.regexScripts[index]!.comment=event.currentTarget.value)}/><select value={script.type} onchange={event=>mutate(draft=>draft.regexScripts[index]!.type=event.currentTarget.value)}><option value="editinput">입력 수정</option><option value="editoutput">출력 수정</option><option value="editrequest">요청 수정</option><option value="editdisplay">표시 수정</option></select><input class="flags" placeholder="flags" value={script.flag} oninput={event=>mutate(draft=>draft.regexScripts[index]!.flag=event.currentTarget.value)}/></div><textarea rows="3" placeholder="찾을 정규식" value={script.in} oninput={event=>mutate(draft=>draft.regexScripts[index]!.in=event.currentTarget.value)}></textarea><textarea rows="4" placeholder="바꿀 내용" value={script.out} oninput={event=>mutate(draft=>draft.regexScripts[index]!.out=event.currentTarget.value)}></textarea><button class="danger" onclick={()=>mutate(draft=>draft.regexScripts.splice(index,1))}><Icon name="trash"/> 삭제</button></article>{/each}<div class="section-head"><div><h3>트리거 스크립트 · {document.draft.triggerScripts.length}개</h3><p>고급 호환 편집입니다. JSON 배열을 수정한 뒤 초안에 적용하세요.</p></div></div><textarea class="raw" rows="18" bind:value={triggerText}></textarea><button class="add" onclick={applyTriggers}>트리거 JSON을 초안에 적용</button></section>
      {:else if tab==='advanced'}<section class="form"><h2>고급 원본 JSON</h2><p>지원하지 않는 확장 필드도 여기서 확인할 수 있습니다. 적용 후 반드시 카드 저장을 눌러야 원본 파일에 반영됩니다.</p><textarea class="raw" rows="30" bind:value={rawText}></textarea><button class="add" onclick={applyRaw}>JSON 초안에 적용</button></section>
      {:else}<section class="studio"><EditorPage embedded initialCard={document.source}/></section>{/if}
    </main>
  </section>
</div>

<style>
  .scrim{position:fixed;inset:0;z-index:70;background:#000a;display:flex;justify-content:flex-end}.workspace{width:min(1120px,calc(100vw - 72px));height:100dvh;display:grid;grid-template-rows:auto auto 1fr;background:#14171d;color:#e8eaf0;box-shadow:-12px 0 40px #000a}.workspace>header{display:flex;align-items:center;gap:10px;padding:11px 15px;border-bottom:1px solid #323743}.workspace>header div{display:grid;min-width:180px}.workspace>header small{color:#7f8795;font:10px ui-monospace}.workspace>header span{margin-right:auto;color:#858c99;font-size:12px}.workspace>header span.dirty{color:#e4b968}.workspace button{cursor:pointer}.workspace>header button,.add,.danger{display:inline-flex;align-items:center;justify-content:center;gap:6px;padding:7px 10px;border:1px solid #414856;border-radius:6px;background:#222731;color:#dce1ea}.workspace>header .save{border-color:#5d8051;background:#293825;color:#d2efc5}.workspace>header .close{width:36px;font-size:24px;background:transparent;border:0}.workspace>nav{display:flex;gap:2px;overflow-x:auto;padding:0 12px;border-bottom:1px solid #303540}.workspace>nav button{white-space:nowrap;padding:10px;border:0;border-bottom:2px solid transparent;background:transparent;color:#8e96a5}.workspace>nav button.active{border-color:#7ea3ef;color:#edf3ff}.workspace>main{overflow:auto;padding:18px 22px}.workspace section{max-width:920px;margin:auto}.form{display:grid;gap:14px}.form label,.lore-form label{display:grid;gap:6px;color:#aeb5c1;font-size:12px}input,textarea,select{box-sizing:border-box;width:100%;padding:9px;border:1px solid #383e4b;border-radius:6px;background:#101319;color:#e7eaf0}textarea{resize:vertical;font:13px/1.5 ui-monospace}.section-head{display:flex;align-items:center;gap:12px;margin-bottom:12px}.section-head>div,.section-head>h3{margin-right:auto}.section-head h2,.section-head p{margin:0}.section-head p,.form>p{color:#8f97a5}.greeting,.regex{display:grid;gap:8px;padding:12px;border:1px solid #343a46;border-radius:8px}.greeting button,.regex .danger,.lore-form .danger{justify-self:end}.danger{border-color:#6e3d47;background:#321f25;color:#e5adb5}.lore-list{display:grid;gap:7px}.lore-list details{border:1px solid #343a46;border-radius:7px;background:#191d24}.lore-list summary{display:grid;grid-template-columns:auto minmax(100px,1fr) minmax(100px,1fr);align-items:center;gap:9px;padding:10px;cursor:pointer}.lore-list summary input{width:auto}.lore-list summary small{overflow:hidden;text-overflow:ellipsis;color:#7f8795}.lore-form{display:grid;gap:10px;padding:12px;border-top:1px solid #343a46}.checks{display:flex;gap:14px;flex-wrap:wrap}.checks label{display:flex;align-items:center;gap:5px}.checks input{width:auto}.search{margin-bottom:12px}.assets{display:grid;grid-template-columns:repeat(auto-fill,minmax(150px,1fr));gap:10px}.assets article{display:grid;gap:7px;padding:8px;border:1px solid #343a46;border-radius:7px;background:#181c22}.assets img,.file{width:100%;height:130px;object-fit:contain;border-radius:5px;background:#0c0f13}.file{display:grid;place-content:center;text-align:center;color:#8f98a8}.assets small{color:#7f8795}.more{display:flex;margin:14px auto}.hidden{display:none}.regex>div{display:grid;grid-template-columns:1fr 160px 80px;gap:7px}.raw{min-height:60vh}.studio{max-width:none}.studio :global(.editor){min-height:calc(100dvh - 150px)}@media(max-width:720px){.workspace{width:100vw}.workspace>header{flex-wrap:wrap}.workspace>header span{order:3;width:100%}.workspace>main{padding:14px 10px}.regex>div{grid-template-columns:1fr}.lore-list summary{grid-template-columns:auto 1fr}.lore-list summary small{grid-column:2}.studio :global(.editor){grid-template-columns:1fr}}
</style>
